15	#![deny(warnings)]
16	#![allow(non_camel_case_types)]
17	
18	//! Neural Stanford Assay — parallel spike to apcab. Runs the
19	//! StanfordAIMI/stanford-deidentifier-base model via ONNX Runtime on
20	//! HTML fixtures and emits guillemet-delimited findings. No engine
21	//! integration; comparative evidence only.
22	//!
23	//! Byte-offset discipline: tokenizer is fed UTF-8 bytes of each line,
24	//! and returned offsets are byte offsets in that line's string. The
25	//! authoritative unit everywhere is UTF-8 bytes — matching apcab.
26	//! Tokenizer offsets are added to each line's byte position in the
27	//! full plain_text to produce document-wide byte offsets.
28	//!
29	//! Usage: apcnsa <input-directory>
30	//! Env:
31	//!   APCNSA_MODEL_DIR   — directory holding model.onnx, tokenizer.json, config.json
32	//!   BURD_OUTPUT_DIR    — where to write {stem}.stanford.assay.txt
33	
34	// RCG output discipline: all emission via apcrl_*! — no direct println!/eprintln!
35	
36	use apcd::apcrp_parse::apcrp_parse;
37	
38	use ort::session::{builder::GraphOptimizationLevel, Session};
39	use ort::value::Value;
40	use serde_json::Value as JsonValue;
41	use tokenizers::tokenizer::Tokenizer;
42	
43	use std::collections::HashMap;
44	use std::path::{Path, PathBuf};
45	
46	// ---------------------------------------------------------------------------
47	// Finding type — document-wide byte offsets into plain_text.
48	// ---------------------------------------------------------------------------
49	
50	#[derive(Debug, Clone)]
51	struct apcnsa_Finding {
52	    offset: usize, // byte offset in plain_text
53	    length: usize, // byte length in plain_text
54	    label:  String, // stanford raw label (e.g., "NAME", "DATE"), "-" prefix stripped
55	}
56	
57	// ---------------------------------------------------------------------------
58	// Main
59	// ---------------------------------------------------------------------------
60	
61	fn main() {
62	    let args: Vec<String> = std::env::args().collect();
63	    if args.len() != 2 {
64	        apcd::apcrl_fatal_now!("usage: apcnsa <input-directory>");
65	    }
66	    let input_dir = &args[1];
67	
68	    let model_dir = std::env::var("APCNSA_MODEL_DIR")
69	        .unwrap_or_else(|_| apcd::apcrl_fatal_now!("APCNSA_MODEL_DIR not set"));
70	    let output_dir = std::env::var("BURD_OUTPUT_DIR")
71	        .unwrap_or_else(|_| apcd::apcrl_fatal_now!("BURD_OUTPUT_DIR not set"));
72	
73	    let model_dir = PathBuf::from(&model_dir);
74	    let model_path     = model_dir.join("model.onnx");
75	    let tokenizer_path = model_dir.join("tokenizer.json");
76	    let config_path    = model_dir.join("config.json");
77	
78	    for p in [&model_path, &tokenizer_path, &config_path] {
79	        if !p.exists() {
80	            apcd::apcrl_fatal_now!(
81	                "missing artifact: {} (run apcw-nsi to populate {})",
82	                p.display(), model_dir.display()
83	            );
84	        }
85	    }
86	
87	    let entries: Vec<_> = std::fs::read_dir(input_dir)
88	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!(
89	            "failed to read directory {}: {}", input_dir, e
90	        ))
91	        .filter_map(|entry| {
92	            let entry = entry.ok()?;
93	            let path = entry.path();
94	            if path.extension().and_then(|e| e.to_str()) == Some("html") {
95	                Some(path)
96	            } else {
97	                None
98	            }
99	        })
100	        .collect();
101	
102	    if entries.is_empty() {
103	        apcd::apcrl_fatal_now!("no .html files found in {}", input_dir);
104	    }
105	
106	    apcd::apcrl_info_now!("loading tokenizer: {}", tokenizer_path.display());
107	    let tokenizer = Tokenizer::from_file(&tokenizer_path)
108	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("tokenizer load: {}", e));
109	
110	    apcd::apcrl_info_now!("loading id2label: {}", config_path.display());
111	    let id2label = zapcnsa_load_id2label(&config_path);
112	
113	    apcd::apcrl_info_now!("loading ONNX model: {}", model_path.display());
114	    let mut session = Session::builder()
115	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("session builder: {}", e))
116	        .with_optimization_level(GraphOptimizationLevel::Level3)
117	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("optimization level: {}", e))
118	        .commit_from_file(&model_path)
119	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("model load: {}", e));
120	
121	    let input_names: Vec<String> = session.inputs().iter().map(|i| i.name().to_string()).collect();
122	    apcd::apcrl_info_now!("model inputs: {:?}", input_names);
123	    let needs_token_type_ids = input_names.iter().any(|n| n == "token_type_ids");
124	
125	    let mut processed = 0u32;
126	    for path in &entries {
127	        let stem = path.file_stem()
128	            .and_then(|s| s.to_str())
129	            .unwrap_or("unknown");
130	
131	        apcd::apcrl_info_now!("processing: {}", path.display());
132	
133	        let html = std::fs::read_to_string(path)
134	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!(
135	                "failed to read {}: {}", path.display(), e
136	            ));
137	
138	        let doc = apcrp_parse(&html);
139	        let t_start = std::time::Instant::now();
140	        let findings = zapcnsa_analyze(
141	            &doc.plain_text, &tokenizer, &mut session, &id2label, needs_token_type_ids,
142	        );
143	        let elapsed_ms = t_start.elapsed().as_millis();
144	
145	        let assay_text = zapcnsa_render_assay(&doc.plain_text, &findings);
146	
147	        let output_path = Path::new(&output_dir)
148	            .join(format!("{}.stanford.assay.txt", stem));
149	        std::fs::write(&output_path, &assay_text)
150	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!(
151	                "failed to write {}: {}", output_path.display(), e
152	            ));
153	
154	        apcd::apcrl_info_now!(
155	            "wrote {} ({} bytes, {} findings, {}ms)",
156	            output_path.display(), assay_text.len(), findings.len(), elapsed_ms
157	        );
158	        processed += 1;
159	    }
160	
161	    apcd::apcrl_info_now!(
162	        "neural stanford assay complete — {} files processed", processed
163	    );
164	}
