166	// ---------------------------------------------------------------------------
167	// Label map
168	// ---------------------------------------------------------------------------
169	
170	fn zapcnsa_load_id2label(config_path: &Path) -> Vec<String> {
171	    let text = std::fs::read_to_string(config_path)
172	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("config read: {}", e));
173	    let json: JsonValue = serde_json::from_str(&text)
174	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("config parse: {}", e));
175	    let map = json.get("id2label")
176	        .unwrap_or_else(|| apcd::apcrl_fatal_now!("config.json missing id2label"))
177	        .as_object()
178	        .unwrap_or_else(|| apcd::apcrl_fatal_now!("id2label not an object"));
179	
180	    let mut pairs: Vec<(usize, String)> = Vec::with_capacity(map.len());
181	    for (k, v) in map {
182	        let id: usize = k.parse()
183	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!("id2label key '{}': {}", k, e));
184	        let label = v.as_str()
185	            .unwrap_or_else(|| apcd::apcrl_fatal_now!("id2label[{}] not a string", k))
186	            .to_string();
187	        pairs.push((id, label));
188	    }
189	    pairs.sort_by_key(|(id, _)| *id);

